import {act} from '@testing-library/react-hooks'

import {
  renderUseMultipleSelection,
  renderMultipleCombobox,
  clickOnSelectedItemAtIndex,
  getSelectedItemAtIndex,
  focusSelectedItemAtIndex,
  keyDownOnSelectedItemAtIndex,
  getSelectedItems,
  getInput,
  items,
  tab,
} from '../testUtils'

describe('getSelectedItemProps', () => {
  test('throws error if no index or item has been passed', () => {
    const {result} = renderUseMultipleSelection()

    expect(result.current.getSelectedItemProps).toThrowError(
      'Pass either selectedItem or index in getSelectedItemProps!',
    )
  })

  describe('hook props', () => {
    test("assign '-1' to tabindex for a non-active item", () => {
      const {result} = renderUseMultipleSelection()
      const itemProps = result.current.getSelectedItemProps({
        index: 0,
        selectedItem: items[0],
      })

      expect(itemProps.tabIndex).toEqual(-1)
    })

    test("assign '0' to tabindex for an active item", () => {
      const {result} = renderUseMultipleSelection({activeIndex: 0})
      const itemProps = result.current.getSelectedItemProps({
        index: 0,
        selectedItem: items[0],
      })

      expect(itemProps.tabIndex).toEqual(0)
    })
  })

  describe('user props', () => {
    test('are passed down', () => {
      const {result} = renderUseMultipleSelection()

      expect(
        result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          foo: 'bar',
        }),
      ).toHaveProperty('foo', 'bar')
    })

    test('custom ref passed by the user is used', () => {
      const {result} = renderUseMultipleSelection()
      const refFn = jest.fn()
      const itemNode = {}

      act(() => {
        const {ref} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          ref: refFn,
        })

        ref(itemNode)
      })

      expect(refFn).toHaveBeenCalledTimes(1)
      expect(refFn).toHaveBeenCalledWith(itemNode)
    })

    test('custom ref with custom name passed by the user is used', () => {
      const {result} = renderUseMultipleSelection()
      const refFn = jest.fn()
      const itemNode = {}

      act(() => {
        const {blablaRef} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          refKey: 'blablaRef',
          blablaRef: refFn,
        })

        blablaRef(itemNode)
      })

      expect(refFn).toHaveBeenCalledTimes(1)
      expect(refFn).toHaveBeenCalledWith(itemNode)
    })

    test('event handler onClick is called along with downshift handler', () => {
      const userOnClick = jest.fn()
      const {result} = renderUseMultipleSelection({
        initialSelectedItems: [items[0], items[1]],
      })

      act(() => {
        const {onClick} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          onClick: userOnClick,
        })

        onClick({})
      })

      expect(userOnClick).toHaveBeenCalledTimes(1)
      expect(result.current.activeIndex).toBe(1)
    })

    test("event handler onClick is called without downshift handler if 'preventDownshiftDefault' is passed in user event", () => {
      const userOnClick = jest.fn(event => {
        event.preventDownshiftDefault = true
      })
      const {result} = renderUseMultipleSelection({
        initialSelectedItems: [items[0], items[1]],
      })

      act(() => {
        const {onClick} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          onClick: userOnClick,
        })

        onClick({})
      })

      expect(userOnClick).toHaveBeenCalledTimes(1)
      expect(result.current.activeIndex).toBe(-1)
    })

    test('event handler onKeyDown is called along with downshift handler', () => {
      const userOnKeyDown = jest.fn()
      const {result} = renderUseMultipleSelection({
        initialSelectedItems: [items[0], items[1]],
      })

      act(() => {
        const {onKeyDown} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          onKeyDown: userOnKeyDown,
        })

        onKeyDown({key: 'ArrowLeft'})
      })

      expect(userOnKeyDown).toHaveBeenCalledTimes(1)
      expect(result.current.activeIndex).toBe(0)
    })

    test("event handler onKeyDown is called without downshift handler if 'preventDownshiftDefault' is passed in user event", () => {
      const userOnKeyDown = jest.fn(event => {
        event.preventDownshiftDefault = true
      })
      const {result} = renderUseMultipleSelection({
        initialSelectedItems: [items[0], items[1]],
      })

      act(() => {
        const {onKeyDown} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          onKeyDown: userOnKeyDown,
        })

        onKeyDown({key: 'ArrowLeft'})
      })

      expect(userOnKeyDown).toHaveBeenCalledTimes(1)
      expect(result.current.activeIndex).toBe(-1)
    })
  })

  describe('event handlers', () => {
    describe('on click', () => {
      test('sets tabindex to "0"', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {initialSelectedItems: [items[0], items[1]]},
        })

        await clickOnSelectedItemAtIndex(0)

        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(0)).toHaveFocus()
        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '-1')
      })

      test('keeps tabindex "0" to an already active item', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1]],
            initialActiveIndex: 0,
          },
        })

        await clickOnSelectedItemAtIndex(0)

        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(0)).toHaveFocus()
      })
    })

    describe('on key down', () => {
      test('arrow left should change active item descendently', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1]],
            initialActiveIndex: 1,
          },
        })

        await keyDownOnSelectedItemAtIndex(1, '{ArrowLeft}')

        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(0)).toHaveFocus()
      })

      test(`arrow left should not change active item if it's the first one added`, async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1]],
            initialActiveIndex: 0,
          },
        })

        await keyDownOnSelectedItemAtIndex(0, '{ArrowLeft}')

        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(0)).toHaveFocus()
      })

      test('arrow right should change active item ascendently', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1]],
            initialActiveIndex: 0,
          },
        })

        await keyDownOnSelectedItemAtIndex(0, '{ArrowRight}')

        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(1)).toHaveFocus()
      })

      test(`arrow right should make no item active if it's on last one added`, async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1]],
            initialActiveIndex: 1,
          },
        })

        await keyDownOnSelectedItemAtIndex(1, '{ArrowRight}')

        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')
        expect(getInput()).toHaveFocus()
      })

      test('arrow navigation moves focus back and forth', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1], items[2]],
            initialActiveIndex: 2,
          },
        })

        await keyDownOnSelectedItemAtIndex(2, '{ArrowLeft}')

        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')

        await keyDownOnSelectedItemAtIndex(1, '{ArrowLeft}')

        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '-1')

        await keyDownOnSelectedItemAtIndex(0, '{ArrowRight}')

        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')

        await keyDownOnSelectedItemAtIndex(2, '{ArrowRight}')

        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')
      })

      test('backspace removes item and moves focus to next item if any', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1], items[2]],
            initialActiveIndex: 1,
          },
        })

        await keyDownOnSelectedItemAtIndex(1, '{Backspace}')

        expect(getSelectedItems()).toHaveLength(2)
        expect(getSelectedItemAtIndex(1)).toHaveFocus()
        expect(getSelectedItemAtIndex(1)).toHaveTextContent(items[2])
      })

      test('backspace removes item and moves focus to input if no items left', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0]],
            initialActiveIndex: 0,
          },
        })

        await keyDownOnSelectedItemAtIndex(0, '{Backspace}')

        expect(getSelectedItems()).toHaveLength(0)
        expect(getInput()).toHaveFocus()
      })

      test('backspace removes item and moves focus to previous item if it was the last in the array', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1], items[2]],
            initialActiveIndex: 2,
          },
        })

        await keyDownOnSelectedItemAtIndex(2, '{Backspace}')

        expect(getSelectedItems()).toHaveLength(2)
        expect(getSelectedItemAtIndex(1)).toHaveFocus()
        expect(getSelectedItemAtIndex(1)).toHaveTextContent(items[1])
      })

      test('delete removes item and moves focus to next item if any', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1], items[2]],
            initialActiveIndex: 1,
          },
        })

        await keyDownOnSelectedItemAtIndex(1, '{Delete}')

        expect(getSelectedItems()).toHaveLength(2)
        expect(getSelectedItemAtIndex(1)).toHaveFocus()
        expect(getSelectedItemAtIndex(1)).toHaveTextContent(items[2])
      })

      test('delete removes item and moves focus to input if no items left', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0]],
            initialActiveIndex: 0,
          },
        })

        await keyDownOnSelectedItemAtIndex(0, '{Delete}')

        expect(getSelectedItems()).toHaveLength(0)
        expect(getInput()).toHaveFocus()
      })

      test('delete removes item and moves focus to previous item if it was the last in the array', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1], items[2]],
            initialActiveIndex: 2,
          },
        })

        await keyDownOnSelectedItemAtIndex(2, '{Delete}')

        expect(getSelectedItems()).toHaveLength(2)
        expect(getSelectedItemAtIndex(1)).toHaveFocus()
        expect(getSelectedItemAtIndex(1)).toHaveTextContent(items[1])
      })

      test('navigation works correctly with both click and arrow keys', async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {
            initialSelectedItems: [items[0], items[1], items[2]],
          },
        })

        await clickOnSelectedItemAtIndex(1)

        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '-1')

        await keyDownOnSelectedItemAtIndex(1, '{ArrowLeft}')

        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '-1')

        await clickOnSelectedItemAtIndex(1)

        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')

        await keyDownOnSelectedItemAtIndex(2, '{ArrowRight}')

        expect(getSelectedItemAtIndex(2)).toHaveAttribute('tabindex', '0')
        expect(getSelectedItemAtIndex(1)).toHaveAttribute('tabindex', '-1')
        expect(getSelectedItemAtIndex(0)).toHaveAttribute('tabindex', '-1')
      })

      test("other than the ones supported don't affect anything", async () => {
        renderMultipleCombobox({
          multipleSelectionProps: {initialSelectedItems: [items[0], items[1]]},
        })

        await keyDownOnSelectedItemAtIndex(1, '{Alt}')
        await keyDownOnSelectedItemAtIndex(1, '{Control}')

import {getDefaultValue} from './utils'
import * as stateChangeTypes from './stateChangeTypes'

/* eslint-disable complexity */
export default function downshiftMultipleSelectionReducer(state, action) {
  const {type, index, props, selectedItem} = action
  const {activeIndex, selectedItems} = state
  let changes

  switch (type) {
    case stateChangeTypes.SelectedItemClick:
      changes = {
        activeIndex: index,
      }

      break
    case stateChangeTypes.SelectedItemKeyDownNavigationPrevious:
      changes = {
        activeIndex: activeIndex - 1 < 0 ? 0 : activeIndex - 1,
      }

      break
    case stateChangeTypes.SelectedItemKeyDownNavigationNext:
      changes = {
        activeIndex:
          activeIndex + 1 >= selectedItems.length ? -1 : activeIndex + 1,
      }

      break
    case stateChangeTypes.SelectedItemKeyDownBackspace:
    case stateChangeTypes.SelectedItemKeyDownDelete: {
      let newActiveIndex = activeIndex

      if (selectedItems.length === 1) {
        newActiveIndex = -1
      } else if (activeIndex === selectedItems.length - 1) {
        newActiveIndex = selectedItems.length - 2
      }

      changes = {
        selectedItems: [
          ...selectedItems.slice(0, activeIndex),
          ...selectedItems.slice(activeIndex + 1),
        ],
        ...{activeIndex: newActiveIndex},
      }

      break
    }
    case stateChangeTypes.DropdownKeyDownNavigationPrevious:
      changes = {
        activeIndex: selectedItems.length - 1,
      }
      break
    case stateChangeTypes.DropdownKeyDownBackspace:
      changes = {
        selectedItems: selectedItems.slice(0, selectedItems.length - 1),
      }
      break
    case stateChangeTypes.FunctionAddSelectedItem:
      changes = {
        selectedItems: [...selectedItems, selectedItem],
      }
      break
    case stateChangeTypes.DropdownClick:
      changes = {
        activeIndex: -1,
      }
      break
    case stateChangeTypes.FunctionRemoveSelectedItem: {
      let newActiveIndex = activeIndex
      const selectedItemIndex = selectedItems.indexOf(selectedItem)

      if (selectedItemIndex >= 0) {
        if (selectedItems.length === 1) {
          newActiveIndex = -1
        } else if (selectedItemIndex === selectedItems.length - 1) {
          newActiveIndex = selectedItems.length - 2
        }

        changes = {
          selectedItems: [
            ...selectedItems.slice(0, selectedItemIndex),
            ...selectedItems.slice(selectedItemIndex + 1),
          ],
          activeIndex: newActiveIndex,
        }
      }
      break
    }
    case stateChangeTypes.FunctionSetSelectedItems: {
      const {selectedItems: newSelectedItems} = action
      changes = {
        selectedItems: newSelectedItems,
      }
      break
    }
    case stateChangeTypes.FunctionSetActiveIndex: {
      const {activeIndex: newActiveIndex} = action
      changes = {
        activeIndex: newActiveIndex,
      }
      break
    }
    case stateChangeTypes.FunctionReset:
      changes = {
        activeIndex: getDefaultValue(props, 'activeIndex'),
        selectedItems: getDefaultValue(props, 'selectedItems'),
      }
      break
    default:
      throw new Error('Reducer called without proper action type.')
  }

  return {
    ...state,
    ...changes,
  }
}
import {useRef, useEffect, useCallback, useMemo} from 'react'
import setStatus from '../../set-a11y-status'
import {handleRefs, callAllEventHandlers, normalizeArrowKey} from '../../utils'
import {
  useControlledReducer,
  getItemIndex,
  useGetterPropsCalledChecker,
  useLatestRef,
  useControlPropsValidator,
} from '../utils'
import {
  getInitialState,
  defaultProps,
  isKeyDownOperationPermitted,
  validatePropTypes,
} from './utils'
import downshiftMultipleSelectionReducer from './reducer'
import * as stateChangeTypes from './stateChangeTypes'

useMultipleSelection.stateChangeTypes = stateChangeTypes

function useMultipleSelection(userProps = {}) {
  validatePropTypes(userProps, useMultipleSelection)
  // Props defaults and destructuring.
  const props = {
    ...defaultProps,
    ...userProps,
  }
  const {
    getA11yRemovalMessage,
    itemToString,
    environment,
    keyNavigationNext,
    keyNavigationPrevious,
  } = props

  // Reducer init.
  const [state, dispatch] = useControlledReducer(
    downshiftMultipleSelectionReducer,
    getInitialState(props),
    props,
  )
  const {activeIndex, selectedItems} = state

  // Refs.
  const isInitialMountRef = useRef(true)
  const dropdownRef = useRef(null)
  const previousSelectedItemsRef = useRef(selectedItems)
  const selectedItemRefs = useRef()
  selectedItemRefs.current = []
  const latest = useLatestRef({state, props})

  // Effects.
  /* Sets a11y status message on changes in selectedItem. */
  useEffect(() => {
    if (isInitialMountRef.current) {
      return
    }

    if (selectedItems.length < previousSelectedItemsRef.current.length) {
      const removedSelectedItem = previousSelectedItemsRef.current.find(
        item => selectedItems.indexOf(item) < 0,
      )

      setStatus(
        getA11yRemovalMessage({
          itemToString,
          resultCount: selectedItems.length,
          removedSelectedItem,
          activeIndex,
          activeSelectedItem: selectedItems[activeIndex],
        }),
        environment.document,
      )
    }

    previousSelectedItemsRef.current = selectedItems

    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedItems.length])
  // Sets focus on active item.
  useEffect(() => {
    if (isInitialMountRef.current) {
      return
    }

    if (activeIndex === -1 && dropdownRef.current) {
      dropdownRef.current.focus()
    } else if (selectedItemRefs.current[activeIndex]) {
      selectedItemRefs.current[activeIndex].focus()
    }
  }, [activeIndex])
  useControlPropsValidator({
    isInitialMount: isInitialMountRef.current,
    props,
    state,
  })
  const setGetterPropCallInfo = useGetterPropsCalledChecker('getDropdownProps')
  // Make initial ref false.
  useEffect(() => {
    isInitialMountRef.current = false

    return () => {
      isInitialMountRef.current = true
    }
  }, [])

  // Event handler functions.
  const selectedItemKeyDownHandlers = useMemo(
    () => ({
      [keyNavigationPrevious]() {
        dispatch({
          type: stateChangeTypes.SelectedItemKeyDownNavigationPrevious,
        })
      },
      [keyNavigationNext]() {
        dispatch({
          type: stateChangeTypes.SelectedItemKeyDownNavigationNext,
        })
      },
      Delete() {
        dispatch({
          type: stateChangeTypes.SelectedItemKeyDownDelete,
        })
      },
      Backspace() {
        dispatch({
          type: stateChangeTypes.SelectedItemKeyDownBackspace,
        })
      },
    }),
    [dispatch, keyNavigationNext, keyNavigationPrevious],
  )
  const dropdownKeyDownHandlers = useMemo(
    () => ({
      [keyNavigationPrevious](event) {
        if (isKeyDownOperationPermitted(event)) {
          dispatch({
            type: stateChangeTypes.DropdownKeyDownNavigationPrevious,
          })
        }
      },
      Backspace(event) {
        if (isKeyDownOperationPermitted(event)) {
          dispatch({
            type: stateChangeTypes.DropdownKeyDownBackspace,
          })
        }
      },
    }),
    [dispatch, keyNavigationPrevious],
  )

  // Getter props.
  const getSelectedItemProps = useCallback(
    ({
      refKey = 'ref',
      ref,
      onClick,
      onKeyDown,
      selectedItem,
      index,
      ...rest
    } = {}) => {
      const {state: latestState} = latest.current
      const itemIndex = getItemIndex(
        index,
        selectedItem,
        latestState.selectedItems,
      )
      if (itemIndex < 0) {
        throw new Error(
          'Pass either selectedItem or index in getSelectedItemProps!',
        )
      }

      const selectedItemHandleClick = () => {
        dispatch({
          type: stateChangeTypes.SelectedItemClick,
          index,
        })
      }
      const selectedItemHandleKeyDown = event => {
        const key = normalizeArrowKey(event)
        if (key && selectedItemKeyDownHandlers[key]) {
          selectedItemKeyDownHandlers[key](event)
        }
      }

      return {
        [refKey]: handleRefs(ref, selectedItemNode => {
          if (selectedItemNode) {
            selectedItemRefs.current.push(selectedItemNode)
          }
        }),
        tabIndex: index === latestState.activeIndex ? 0 : -1,
        onClick: callAllEventHandlers(onClick, selectedItemHandleClick),
        onKeyDown: callAllEventHandlers(onKeyDown, selectedItemHandleKeyDown),
        ...rest,
      }
    },
    [dispatch, latest, selectedItemKeyDownHandlers],
  )
  const getDropdownProps = useCallback(
    (
      {
        refKey = 'ref',
        ref,
        onKeyDown,
        onClick,
        preventKeyAction = false,
        ...rest
      } = {},
      {suppressRefError = false} = {},
    ) => {
      setGetterPropCallInfo(
        'getDropdownProps',
        suppressRefError,
        refKey,
        dropdownRef,
      )

      const dropdownHandleKeyDown = event => {
        const key = normalizeArrowKey(event)
        if (key && dropdownKeyDownHandlers[key]) {
          dropdownKeyDownHandlers[key](event)
        }
      }
      const dropdownHandleClick = () => {
        dispatch({
          type: stateChangeTypes.DropdownClick,
        })
      }

      return {
        [refKey]: handleRefs(ref, dropdownNode => {
          if (dropdownNode) {
            dropdownRef.current = dropdownNode
          }
        }),
        ...(!preventKeyAction && {
          onKeyDown: callAllEventHandlers(onKeyDown, dropdownHandleKeyDown),
          onClick: callAllEventHandlers(onClick, dropdownHandleClick),
        }),
        ...rest,
      }
    },
    [dispatch, dropdownKeyDownHandlers, setGetterPropCallInfo],
  )

  // returns
  const addSelectedItem = useCallback(
    selectedItem => {
      dispatch({
        type: stateChangeTypes.FunctionAddSelectedItem,
        selectedItem,
      })
    },
    [dispatch],
  )
  const removeSelectedItem = useCallback(
    selectedItem => {
      dispatch({
        type: stateChangeTypes.FunctionRemoveSelectedItem,
        selectedItem,
      })
    },
    [dispatch],
  )
  const setSelectedItems = useCallback(
    newSelectedItems => {
      dispatch({
        type: stateChangeTypes.FunctionSetSelectedItems,
        selectedItems: newSelectedItems,
      })
    },
    [dispatch],
  )
  const setActiveIndex = useCallback(
    newActiveIndex => {
      dispatch({
        type: stateChangeTypes.FunctionSetActiveIndex,
        activeIndex: newActiveIndex,
      })
    },
    [dispatch],
  )
  const reset = useCallback(() => {
    dispatch({
      type: stateChangeTypes.FunctionReset,
    })
  }, [dispatch])

  return {
    getSelectedItemProps,
    getDropdownProps,
    addSelectedItem,
    removeSelectedItem,
    setSelectedItems,
    setActiveIndex,
    reset,
    selectedItems,
    activeIndex,
  }
}

export default useMultipleSelection

import * as React from 'react'

import {render, screen} from '@testing-library/react'
import {renderHook} from '@testing-library/react-hooks'
import {defaultProps} from '../utils'
import {items, user, dataTestIds} from '../testUtils'
import useCombobox from '../useCombobox'
import {getInput, keyDownOnInput} from '../useCombobox/testUtils'
import useMultipleSelection from '.'

export * from '../testUtils'
export {getInput, keyDownOnInput}

jest.mock('../../utils', () => {
  const utils = jest.requireActual('../../utils')

  return {
    ...utils,
    generateId: () => 'test-id',
  }
})

jest.mock('../utils', () => {
  const utils = jest.requireActual('../utils')
  const hooksUtils = jest.requireActual('../../utils')

  return {
    ...utils,
    useGetterPropsCalledChecker: () => hooksUtils.noop,
  }
})

beforeEach(jest.resetAllMocks)
afterAll(jest.restoreAllMocks)

export function getSelectedItemAtIndex(index) {
  return screen.getByTestId(dataTestIds.selectedItem(index))
}

export function getSelectedItems() {
  return screen.queryAllByTestId(new RegExp(dataTestIds.selectedItemPrefix))
}

export async function clickOnSelectedItemAtIndex(index) {
  await user.click(getSelectedItemAtIndex(index))
}
export async function keyDownOnSelectedItemAtIndex(index, key) {
  const selectedItem = getSelectedItemAtIndex(index)

  if (document.activeElement !== selectedItem) {
    selectedItem.focus()
  }

  await user.keyboard(key)
}

export function focusSelectedItemAtIndex(index) {
  getSelectedItemAtIndex(index).focus()
}

export async function clickOnInput() {
  await user.click(getInput())
}

const DropdownMultipleCombobox = ({
  multipleSelectionProps = {},
  comboboxProps = {},
}) => {
  const {getSelectedItemProps, getDropdownProps, selectedItems} =
